use chrono::{DateTime, Utc};
use uuid::Uuid;

use super::todo_title::TodoTitle;
use super::user::UserId;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WaitingForId(Uuid);

impl Default for WaitingForId {
    fn default() -> Self {
        Self::new()
    }
}

impl WaitingForId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

/// Who or what the user is waiting on. Non-empty, max 100 chars, trimmed.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WaitingOn(String);

const WAITING_ON_MAX_LENGTH: usize = 100;

#[derive(Debug, Clone, PartialEq, thiserror::Error)]
pub enum WaitingOnError {
    #[error("Waiting-on cannot be empty")]
    Empty,
    #[error("Waiting-on too long (max {max}, got {actual})")]
    TooLong { max: usize, actual: usize },
}

impl WaitingOn {
    pub fn parse(input: String) -> Result<Self, WaitingOnError> {
        let trimmed = input.trim().to_string();
        if trimmed.is_empty() {
            return Err(WaitingOnError::Empty);
        }
        if trimmed.len() > WAITING_ON_MAX_LENGTH {
            return Err(WaitingOnError::TooLong {
                max: WAITING_ON_MAX_LENGTH,
                actual: trimmed.len(),
            });
        }
        Ok(Self(trimmed))
    }

    pub fn as_str(&self) -> &str {
        &self.0
    }
}

/// An item the user is waiting on from someone else.
///
/// State machine:
///   Active --resolve()--> Resolved (received)
///
/// Resolved items are removed from the active Waiting For list.
#[derive(Debug, Clone)]
pub enum WaitingForItem {
    Active {
        id: WaitingForId,
        user_id: UserId,
        title: TodoTitle,
        waiting_on: WaitingOn,
        created_at: DateTime<Utc>,
    },
    Resolved {
        id: WaitingForId,
        user_id: UserId,
        title: TodoTitle,
        waiting_on: WaitingOn,
        created_at: DateTime<Utc>,
        resolved_at: DateTime<Utc>,
    },
}

impl WaitingForItem {
    pub fn new(user_id: UserId, title: TodoTitle, waiting_on: WaitingOn) -> Self {
        Self::Active {
            id: WaitingForId::new(),
            user_id,
            title,
            waiting_on,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: WaitingForId,
        user_id: UserId,
        title: TodoTitle,
        waiting_on: WaitingOn,
        created_at: DateTime<Utc>,
        resolved_at: Option<DateTime<Utc>>,
    ) -> Self {
        match resolved_at {
            Some(resolved_at) => Self::Resolved {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
                resolved_at,
            },
            None => Self::Active {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
            },
        }
    }

    pub fn id(&self) -> &WaitingForId {
        match self {
            Self::Active { id, .. } | Self::Resolved { id, .. } => id,
        }
    }

    pub fn user_id(&self) -> &UserId {
        match self {
            Self::Active { user_id, .. } | Self::Resolved { user_id, .. } => user_id,
        }
    }

    pub fn title(&self) -> &TodoTitle {
        match self {
            Self::Active { title, .. } | Self::Resolved { title, .. } => title,
        }
    }

    pub fn waiting_on(&self) -> &WaitingOn {
        match self {
            Self::Active { waiting_on, .. } | Self::Resolved { waiting_on, .. } => waiting_on,
        }
    }

    pub fn created_at(&self) -> &DateTime<Utc> {
        match self {
            Self::Active { created_at, .. } | Self::Resolved { created_at, .. } => created_at,
        }
    }

    pub fn is_active(&self) -> bool {
        matches!(self, Self::Active { .. })
    }

    pub fn is_resolved(&self) -> bool {
        matches!(self, Self::Resolved { .. })
    }

    /// Transitions an Active waiting-for item to Resolved (received).
    /// If already resolved, returns self unchanged.
    pub fn resolve(self) -> Self {
        match self {
            Self::Active {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
            } => Self::Resolved {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
                resolved_at: Utc::now(),
            },
            resolved @ Self::Resolved { .. } => resolved,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn waiting_for_id_is_unique() {
        let id1 = WaitingForId::new();
        let id2 = WaitingForId::new();
        assert_ne!(id1, id2);
    }

    #[test]
    fn waiting_for_id_from_uuid_roundtrips() {
        let uuid = Uuid::new_v4();
        let id = WaitingForId::from_uuid(uuid);
        assert_eq!(id.as_uuid(), &uuid);
    }

    #[test]
    fn valid_waiting_on_is_accepted() {
        let waiting_on = WaitingOn::parse("Alice".to_string()).unwrap();
        assert_eq!(waiting_on.as_str(), "Alice");
    }

    #[test]
    fn waiting_on_is_trimmed() {
        let waiting_on = WaitingOn::parse("  Bob  ".to_string()).unwrap();
        assert_eq!(waiting_on.as_str(), "Bob");
    }

    #[test]
    fn empty_waiting_on_is_rejected() {
        let result = WaitingOn::parse("".to_string());
        assert!(matches!(result, Err(WaitingOnError::Empty)));
    }

    #[test]
    fn whitespace_only_waiting_on_is_rejected() {
        let result = WaitingOn::parse("   ".to_string());
        assert!(matches!(result, Err(WaitingOnError::Empty)));
    }

    #[test]
    fn waiting_on_at_max_length_is_accepted() {
        let name = "a".repeat(100);
        let waiting_on = WaitingOn::parse(name.clone()).unwrap();
        assert_eq!(waiting_on.as_str(), &name);
    }

    #[test]
    fn waiting_on_exceeding_max_length_is_rejected() {
        let name = "a".repeat(101);
        let result = WaitingOn::parse(name);
        assert!(matches!(
            result,
            Err(WaitingOnError::TooLong { max: 100, .. })
        ));
    }

    #[test]
    fn new_waiting_for_item_is_active() {
        let user_id = UserId::new();
        let title = TodoTitle::parse("Fix server bug".to_string()).unwrap();
        let waiting_on = WaitingOn::parse("DevOps team".to_string()).unwrap();
        let item = WaitingForItem::new(user_id, title, waiting_on);

        assert!(item.is_active());
        assert!(!item.is_resolved());
        assert_eq!(item.title().as_str(), "Fix server bug");
        assert_eq!(item.waiting_on().as_str(), "DevOps team");
    }

    #[test]
    fn new_waiting_for_item_has_user() {
        let user_id = UserId::new();
        let title = TodoTitle::parse("Get approval".to_string()).unwrap();
        let waiting_on = WaitingOn::parse("Manager".to_string()).unwrap();
        let item = WaitingForItem::new(user_id.clone(), title, waiting_on);

        assert_eq!(item.user_id(), &user_id);
    }

    #[test]
    fn resolve_transitions_active_to_resolved() {
        let item = WaitingForItem::new(
            UserId::new(),
            TodoTitle::parse("Receive package".to_string()).unwrap(),
            WaitingOn::parse("Amazon".to_string()).unwrap(),
        );

        let resolved = item.resolve();
        assert!(resolved.is_resolved());
        assert!(!resolved.is_active());
    }

    #[test]
    fn resolve_preserves_id_and_fields() {
        let user_id = UserId::new();
        let title = TodoTitle::parse("Get quote".to_string()).unwrap();
        let waiting_on = WaitingOn::parse("Contractor".to_string()).unwrap();
        let item = WaitingForItem::new(user_id.clone(), title, waiting_on);
        let id = item.id().clone();

        let resolved = item.resolve();
        assert_eq!(resolved.id(), &id);
        assert_eq!(resolved.user_id(), &user_id);
        assert_eq!(resolved.title().as_str(), "Get quote");
        assert_eq!(resolved.waiting_on().as_str(), "Contractor");
    }

    #[test]
    fn resolve_is_noop_on_resolved_item() {
        let item = WaitingForItem::new(
            UserId::new(),
            TodoTitle::parse("Already received".to_string()).unwrap(),
            WaitingOn::parse("Vendor".to_string()).unwrap(),
        );
        let resolved = item.resolve();
        let still_resolved = resolved.resolve();
        assert!(still_resolved.is_resolved());
    }

    #[test]
    fn from_parts_creates_active_when_no_resolved_at() {
        let id = WaitingForId::new();
        let user_id = UserId::new();
        let title = TodoTitle::parse("Test".to_string()).unwrap();
        let waiting_on = WaitingOn::parse("Someone".to_string()).unwrap();
        let now = Utc::now();

        let item =
            WaitingForItem::from_parts(id.clone(), user_id.clone(), title, waiting_on, now, None);

        assert!(item.is_active());
        assert_eq!(item.id(), &id);
        assert_eq!(item.user_id(), &user_id);
        assert_eq!(item.created_at(), &now);
    }

    #[test]
    fn from_parts_creates_resolved_when_resolved_at_present() {
        let id = WaitingForId::new();
        let user_id = UserId::new();
        let title = TodoTitle::parse("Done".to_string()).unwrap();
        let waiting_on = WaitingOn::parse("Other".to_string()).unwrap();
        let created = Utc::now();
        let resolved = Utc::now();

        let item = WaitingForItem::from_parts(
            id.clone(),
            user_id,
            title,
            waiting_on,
            created,
            Some(resolved),
        );

        assert!(item.is_resolved());
        assert_eq!(item.id(), &id);
    }
}

use chrono::{DateTime, Utc};
use sqlx::{PgExecutor, PgPool};
use uuid::Uuid;

use crate::domain::{TodoTitle, UserId, WaitingForId, WaitingForItem, WaitingOn};

struct WaitingForRecord {
    id: Uuid,
    user_id: Uuid,
    title: String,
    waiting_on: String,
    created_at: DateTime<Utc>,
    resolved_at: Option<DateTime<Utc>>,
}

impl WaitingForRecord {
    fn into_domain(self) -> WaitingForItem {
        let id = WaitingForId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");
        let waiting_on =
            WaitingOn::parse(self.waiting_on).expect("stored waiting_on should be valid");

        WaitingForItem::from_parts(
            id,
            user_id,
            title,
            waiting_on,
            self.created_at,
            self.resolved_at,
        )
    }
}

pub async fn insert_waiting_for_item(
    executor: impl PgExecutor<'_>,
    item: &WaitingForItem,
) -> Result<(), sqlx::Error> {
    let resolved_at: Option<&DateTime<Utc>> = match item {
        WaitingForItem::Resolved { resolved_at, .. } => Some(resolved_at),
        WaitingForItem::Active { .. } => None,
    };

    sqlx::query!(
        r#"INSERT INTO waiting_for_items (id, user_id, title, waiting_on, created_at, resolved_at)
           VALUES ($1, $2, $3, $4, $5 :: timestamptz, $6 :: timestamptz)"#,
        item.id().as_uuid(),
        item.user_id().as_uuid(),
        item.title().as_str(),
        item.waiting_on().as_str(),
        item.created_at() as &DateTime<Utc>,
        resolved_at as Option<&DateTime<Utc>>,
    )
    .execute(executor)
    .await?;
    Ok(())
}

pub async fn find_active_waiting_for_items_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<WaitingForItem>, sqlx::Error> {
    let records = sqlx::query_as!(
        WaitingForRecord,
        r#"SELECT id, user_id, title, waiting_on,
           created_at as "created_at: DateTime<Utc>",
           resolved_at as "resolved_at: DateTime<Utc>"
           FROM waiting_for_items
           WHERE user_id = $1 AND resolved_at IS NULL
           ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records.into_iter().map(|r| r.into_domain()).collect())
}

pub async fn find_waiting_for_item_by_id(
    pool: &PgPool,
    item_id: &WaitingForId,
) -> Result<Option<WaitingForItem>, sqlx::Error> {
    let record: Option<WaitingForRecord> = sqlx::query_as!(
        WaitingForRecord,
        r#"SELECT id, user_id, title, waiting_on,
           created_at as "created_at: DateTime<Utc>",
           resolved_at as "resolved_at: DateTime<Utc>"
           FROM waiting_for_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r| r.into_domain()))
}

pub async fn resolve_waiting_for_item(
    pool: &PgPool,
    item_id: &WaitingForId,
    resolved_at: &DateTime<Utc>,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE waiting_for_items SET resolved_at = $1 :: timestamptz WHERE id = $2"#,
        resolved_at as &DateTime<Utc>,
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn delete_waiting_for_item(
    pool: &PgPool,
    item_id: &WaitingForId,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM waiting_for_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn count_active_waiting_for_items(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM waiting_for_items WHERE user_id = $1 AND resolved_at IS NULL"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

pub async fn update_waiting_for_item(
    pool: &PgPool,
    item_id: &WaitingForId,
    title: &TodoTitle,
    waiting_on: &WaitingOn,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE waiting_for_items SET title = $1, waiting_on = $2 WHERE id = $3"#,
        title.as_str(),
        waiting_on.as_str(),
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

use askama::Template;
use axum::extract::State;
use axum::http::StatusCode;
use axum::response::{Html, IntoResponse, Response};
use sqlx::PgPool;

use super::auth::AuthenticatedUser;
use crate::services::inbox_service;

#[derive(Template)]
#[template(path = "gtd_placeholder.html")]
struct GtdPlaceholderTemplate {
    current_page: &'static str,
    page_title: &'static str,
    heading: &'static str,
    description: &'static str,
    inbox_count: i64,
}

#[derive(Debug, thiserror::Error)]
pub enum GtdPlaceholderError {
    #[error("Failed to render template")]
    Render(#[from] askama::Error),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

impl IntoResponse for GtdPlaceholderError {
    fn into_response(self) -> Response {
        tracing::error!(error = %self, "GTD placeholder error");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Html("<h1>Something went wrong</h1>".to_string()),
        )
            .into_response()
    }
}

async fn render_placeholder(
    user_id: &crate::domain::UserId,
    pool: &PgPool,
    current_page: &'static str,
    page_title: &'static str,
    heading: &'static str,
    description: &'static str,
) -> Result<impl IntoResponse, GtdPlaceholderError> {
    let inbox_count = inbox_service::get_inbox_count(pool, user_id)
        .await
        .map_err(GtdPlaceholderError::Unexpected)?;

    let template = GtdPlaceholderTemplate {
        current_page,
        page_title,
        heading,
        description,
        inbox_count,
    };
    Ok(Html(template.render()?))
}

pub async fn get_someday_maybe(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
) -> Result<impl IntoResponse, GtdPlaceholderError> {
    render_placeholder(
        &user_id,
        &pool,
        "someday_maybe",
        "Someday/Maybe -- Todo List",
        "Someday/Maybe",
        "Ideas and possibilities for the future.",
    )
    .await
}

pub async fn get_review(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
) -> Result<impl IntoResponse, GtdPlaceholderError> {
    render_placeholder(
        &user_id,
        &pool,
        "review",
        "Weekly Review -- Todo List",
        "Weekly Review",
        "Keep your system current and trustworthy.",
    )
    .await
}

