    pub id: String,
    pub title: String,
    pub waiting_on: String,
    pub date_added: String,
    pub date_added_iso: String,
}

#[derive(Template)]
#[template(path = "waiting_for.html")]
struct WaitingForTemplate {
    current_page: &'static str,
    inbox_count: i64,
    items: Vec<WaitingForView>,
    error_message: Option<String>,
}

#[derive(Template)]
#[template(path = "waiting_for_item.html")]
struct WaitingForItemTemplate {
    item: WaitingForView,
}

#[derive(Template)]
#[template(path = "waiting_for_edit.html")]
struct WaitingForEditTemplate {
    item: WaitingForView,
}

fn build_view(item: &crate::domain::WaitingForItem) -> WaitingForView {
    WaitingForView {
        id: item.id().as_uuid().to_string(),
        title: item.title().as_str().to_string(),
        waiting_on: item.waiting_on().as_str().to_string(),
        date_added: item.created_at().format("%b %d, %Y").to_string(),
        date_added_iso: item.created_at().to_rfc3339(),
    }
}

pub async fn get_waiting_for(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
) -> Result<Response, WaitingForError> {
    let inbox_count = inbox_service::get_inbox_count(&pool, &user_id)
        .await
        .map_err(WaitingForError::Unexpected)?;

    let items = waiting_for_service::list_active_waiting_for_items(&pool, &user_id)
        .await
        .map_err(WaitingForError::Unexpected)?;

    let item_views: Vec<WaitingForView> = items.iter().map(build_view).collect();

    let template = WaitingForTemplate {
        current_page: "waiting_for",
        inbox_count,
        items: item_views,
        error_message: None,
    };
    Ok(Html(template.render()?).into_response())
}

#[derive(serde::Deserialize)]
pub struct AddWaitingForForm {
    pub title: String,
    pub waiting_on: String,
}

pub async fn post_waiting_for(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Form(form): Form<AddWaitingForForm>,
) -> Result<Response, WaitingForError> {
    let htmx = is_htmx_request(&headers);

    if form.title.trim().is_empty() {
        if htmx {
            return Ok(StatusCode::NO_CONTENT.into_response());
        }
        return Ok(Redirect::to("/waiting-for").into_response());
    }

    if form.waiting_on.trim().is_empty() {
        if htmx {
            return Ok(StatusCode::NO_CONTENT.into_response());
        }
        return Ok(Redirect::to("/waiting-for").into_response());
    }

    match waiting_for_service::add_waiting_for_item(
        &pool,
        user_id.clone(),
        form.title,
        form.waiting_on,
    )
    .await
    {
        Ok(item) => {
            if htmx {
                let template = WaitingForItemTemplate {
                    item: build_view(&item),
                };
                let body = template.render().map_err(WaitingForError::Render)?;
                Ok(htmx_response_with_announce(
                    Html(body),
                    "Waiting-for item added",
                ))
            } else {
                Ok(Redirect::to("/waiting-for").into_response())
            }
        }
        Err(AddWaitingForError::InvalidTitle(title_err)) => {
            let user_facing = match title_err {
                TodoTitleError::Empty => {
                    if htmx {
                        return Ok(StatusCode::NO_CONTENT.into_response());
                    }
                    return Ok(Redirect::to("/waiting-for").into_response());
                }
                TodoTitleError::TooLong { max, .. } => {
                    format!("That title is too long (max {max} characters)")
                }
            };
            render_waiting_for_with_error(&pool, &user_id, &user_facing).await
        }
        Err(AddWaitingForError::InvalidWaitingOn(person_err)) => {
            let user_facing = match person_err {
                WaitingOnError::Empty => {
                    if htmx {
                        return Ok(StatusCode::NO_CONTENT.into_response());
                    }
                    return Ok(Redirect::to("/waiting-for").into_response());
                }
                WaitingOnError::TooLong { max, .. } => {
                    format!("That name is too long (max {max} characters)")
                }
            };
            render_waiting_for_with_error(&pool, &user_id, &user_facing).await
        }
        Err(AddWaitingForError::Unexpected(err)) => Err(WaitingForError::Unexpected(err)),
    }
}

async fn render_waiting_for_with_error(
    pool: &PgPool,
    user_id: &crate::domain::UserId,
    error_message: &str,
) -> Result<Response, WaitingForError> {
    let inbox_count = inbox_service::get_inbox_count(pool, user_id)
        .await
        .map_err(WaitingForError::Unexpected)?;

    let items = waiting_for_service::list_active_waiting_for_items(pool, user_id)
        .await
        .map_err(WaitingForError::Unexpected)?;

    let item_views: Vec<WaitingForView> = items.iter().map(build_view).collect();

    let template = WaitingForTemplate {
        current_page: "waiting_for",
        inbox_count,
        items: item_views,
        error_message: Some(error_message.to_string()),
    };
    let body = template.render().map_err(WaitingForError::Render)?;
    Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
}

pub async fn post_complete_waiting_for(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Path(item_id): Path<Uuid>,
) -> Result<Response, WaitingForError> {
    let htmx = is_htmx_request(&headers);
    let wf_id = WaitingForId::from_uuid(item_id);

    match waiting_for_service::resolve_waiting_for_item(&pool, &wf_id, &user_id).await {
        Ok(()) => {
            if htmx {
                Ok(htmx_response_with_announce(
                    Html(String::new()),
                    "Item received",
                ))
            } else {
                Ok(Redirect::to("/waiting-for").into_response())
            }
        }
        Err(ResolveWaitingForError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Waiting-for item not found</h1>".to_string()),
        )
            .into_response()),
        Err(ResolveWaitingForError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(ResolveWaitingForError::Unexpected(err)) => Err(WaitingForError::Unexpected(err)),
    }
}

pub async fn post_delete_waiting_for(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Path(item_id): Path<Uuid>,
) -> Result<Response, WaitingForError> {
    let htmx = is_htmx_request(&headers);
    let wf_id = WaitingForId::from_uuid(item_id);

    match waiting_for_service::delete_waiting_for_item(&pool, &wf_id, &user_id).await {
        Ok(()) => {
            if htmx {
                Ok(htmx_response_with_announce(
                    Html(String::new()),
                    "Item deleted",
                ))
            } else {
                Ok(Redirect::to("/waiting-for").into_response())
            }
        }
        Err(DeleteWaitingForError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Waiting-for item not found</h1>".to_string()),
        )
            .into_response()),
        Err(DeleteWaitingForError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(DeleteWaitingForError::Unexpected(err)) => Err(WaitingForError::Unexpected(err)),
    }
}

pub async fn get_edit_waiting_for(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Path(item_id): Path<Uuid>,
) -> Result<Response, WaitingForError> {
    let wf_id = WaitingForId::from_uuid(item_id);
    let item =
        crate::infrastructure::waiting_for_repository::find_waiting_for_item_by_id(&pool, &wf_id)
            .await
            .map_err(|e| WaitingForError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
            .ok_or_else(|| WaitingForError::Unexpected(anyhow::anyhow!("Item not found")))?;

    if item.user_id() != &user_id {
        return Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response());
    }

    let htmx = is_htmx_request(&headers);

    if htmx {
        let template = WaitingForEditTemplate {
            item: build_view(&item),
        };
        let body = template.render().map_err(WaitingForError::Render)?;
        Ok(Html(body).into_response())
    } else {
        Ok(Redirect::to("/waiting-for").into_response())
    }
}

#[derive(serde::Deserialize)]
pub struct EditWaitingForForm {
    pub title: String,
    pub waiting_on: String,
}

pub async fn post_edit_waiting_for(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Path(item_id): Path<Uuid>,
    Form(form): Form<EditWaitingForForm>,
) -> Result<Response, WaitingForError> {
    let htmx = is_htmx_request(&headers);
    let wf_id = WaitingForId::from_uuid(item_id);

    match waiting_for_service::update_waiting_for_item(
        &pool,
        &wf_id,
        &user_id,
        form.title,
        form.waiting_on,
    )
    .await
    {
        Ok(()) => {
            if htmx {
                let item =
                    crate::infrastructure::waiting_for_repository::find_waiting_for_item_by_id(
                        &pool, &wf_id,
                    )
                    .await
                    .map_err(|e| {
                        WaitingForError::Unexpected(anyhow::anyhow!("Database error: {e}"))
                    })?
                    .ok_or_else(|| {
                        WaitingForError::Unexpected(anyhow::anyhow!("Item not found"))
                    })?;

                let template = WaitingForItemTemplate {
                    item: build_view(&item),
                };
                let body = template.render().map_err(WaitingForError::Render)?;
                Ok(htmx_response_with_announce(Html(body), "Item updated"))
            } else {
                Ok(Redirect::to("/waiting-for").into_response())
            }
        }
        Err(UpdateWaitingForError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Waiting-for item not found</h1>".to_string()),
        )
            .into_response()),
        Err(UpdateWaitingForError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(UpdateWaitingForError::InvalidTitle(title_err)) => {
            let user_facing = match title_err {
                TodoTitleError::Empty => "Title cannot be empty".to_string(),
                TodoTitleError::TooLong { max, .. } => {
                    format!("That title is too long (max {max} characters)")
                }
            };
            render_waiting_for_with_error(&pool, &user_id, &user_facing).await
        }
        Err(UpdateWaitingForError::InvalidWaitingOn(person_err)) => {
            let user_facing = match person_err {
                WaitingOnError::Empty => "Who or what cannot be empty".to_string(),
                WaitingOnError::TooLong { max, .. } => {
                    format!("That name is too long (max {max} characters)")
                }
            };
            render_waiting_for_with_error(&pool, &user_id, &user_facing).await
        }
        Err(UpdateWaitingForError::Unexpected(err)) => Err(WaitingForError::Unexpected(err)),
    }
}

pub async fn get_waiting_for_item(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    Path(item_id): Path<Uuid>,
) -> Result<Response, WaitingForError> {
    let wf_id = WaitingForId::from_uuid(item_id);
    let item =
        crate::infrastructure::waiting_for_repository::find_waiting_for_item_by_id(&pool, &wf_id)
            .await
            .map_err(|e| WaitingForError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
            .ok_or_else(|| WaitingForError::Unexpected(anyhow::anyhow!("Item not found")))?;

    if item.user_id() != &user_id {
        return Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response());
    }

    let template = WaitingForItemTemplate {
        item: build_view(&item),
    };
    let body = template.render().map_err(WaitingForError::Render)?;
    Ok(Html(body).into_response())
}

#[derive(Debug, thiserror::Error)]
pub enum WaitingForError {
    #[error("Failed to render template")]
    Render(#[from] askama::Error),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

impl IntoResponse for WaitingForError {
    fn into_response(self) -> Response {
        tracing::error!(error = %self, "Waiting-for error");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Html("<h1>Something went wrong</h1>".to_string()),
        )
            .into_response()
    }
}

use axum::Router;
use sqlx::postgres::PgPoolOptions;
use sqlx::PgPool;
use tokio::net::TcpListener;
use tower_http::request_id::{MakeRequestUuid, PropagateRequestIdLayer, SetRequestIdLayer};
use tower_http::services::ServeDir;
use tower_http::trace::TraceLayer;
use tower_sessions::SessionManagerLayer;
use tower_sessions_sqlx_store::PostgresStore;

use crate::configuration::Settings;
use crate::routes::{
    get_contexts, get_dashboard, get_edit_context, get_edit_next_action, get_edit_project,
    get_edit_todo, get_edit_waiting_for, get_forgot_password, get_inbox, get_login,
    get_next_action_item, get_next_actions, get_project_detail, get_project_item, get_projects,
    get_register, get_review, get_someday_maybe, get_todo_item, get_todos_page, get_waiting_for,
    get_waiting_for_item, health_check, index, post_clarify_inbox_item, post_complete_next_action,
    post_complete_project, post_complete_waiting_for, post_context, post_delete_context,
    post_delete_inbox_item, post_delete_next_action, post_delete_project, post_delete_todo,
    post_delete_waiting_for, post_edit_context, post_edit_next_action, post_edit_project,
    post_edit_todo, post_edit_waiting_for, post_inbox, post_login, post_logout, post_next_action,
    post_project, post_project_next_action, post_register, post_todo, post_toggle_todo,
    post_waiting_for,
};

pub struct Application {
    listener: TcpListener,
    pool: PgPool,
}

impl Application {
    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
        let pool = PgPoolOptions::new()
            .max_connections(5)
            .connect_with(settings.database.connect_options())
            .await?;

        sqlx::migrate!("./migrations").run(&pool).await?;

        let session_store = PostgresStore::new(pool.clone());
        session_store.migrate().await?;

        let address = format!(
            "{}:{}",
            settings.application.host, settings.application.port
        );
        let listener = TcpListener::bind(&address).await?;

        tracing::info!("Listening on {}", listener.local_addr()?);

        Ok(Self { listener, pool })
    }

    pub fn port(&self) -> u16 {
        self.listener.local_addr().unwrap().port()
    }

    pub fn router(pool: PgPool) -> Router {
        let x_request_id = axum::http::HeaderName::from_static("x-request-id");

        let session_store = PostgresStore::new(pool.clone());
        let session_layer = SessionManagerLayer::new(session_store);

        Router::new()
            .route("/", axum::routing::get(index))
            .route("/dashboard", axum::routing::get(get_dashboard))
            .route("/inbox", axum::routing::get(get_inbox).post(post_inbox))
            .route(
                "/inbox/{id}/delete",
                axum::routing::post(post_delete_inbox_item),
            )
            .route(
                "/inbox/{id}/clarify",
                axum::routing::post(post_clarify_inbox_item),
            )
            .route(
                "/contexts",
                axum::routing::get(get_contexts).post(post_context),
            )
            .route(
                "/contexts/{id}/edit",
                axum::routing::get(get_edit_context).post(post_edit_context),
            )
            .route(
                "/contexts/{id}/delete",
                axum::routing::post(post_delete_context),
            )
            .route(
                "/next-actions",
                axum::routing::get(get_next_actions).post(post_next_action),
            )
            .route(
                "/next-actions/{id}",
                axum::routing::get(get_next_action_item),
            )
            .route(
                "/next-actions/{id}/complete",
                axum::routing::post(post_complete_next_action),
            )
            .route(
                "/next-actions/{id}/delete",
                axum::routing::post(post_delete_next_action),
            )
            .route(
                "/next-actions/{id}/edit",
                axum::routing::get(get_edit_next_action).post(post_edit_next_action),
            )
            .route(
                "/projects",
                axum::routing::get(get_projects).post(post_project),
            )
            .route("/projects/{id}", axum::routing::get(get_project_detail))
            .route("/projects/{id}/item", axum::routing::get(get_project_item))
            .route(
                "/projects/{id}/complete",
                axum::routing::post(post_complete_project),
            )
            .route(
                "/projects/{id}/delete",
                axum::routing::post(post_delete_project),
            )
            .route(
                "/projects/{id}/edit",
                axum::routing::get(get_edit_project).post(post_edit_project),
            )
            .route(
                "/projects/{id}/next-actions",
                axum::routing::post(post_project_next_action),
            )
            .route(
                "/waiting-for",
                axum::routing::get(get_waiting_for).post(post_waiting_for),
            )
            .route(
                "/waiting-for/{id}",
                axum::routing::get(get_waiting_for_item),
            )
            .route(
                "/waiting-for/{id}/complete",
                axum::routing::post(post_complete_waiting_for),
            )
            .route(
                "/waiting-for/{id}/delete",
                axum::routing::post(post_delete_waiting_for),
            )
            .route(
                "/waiting-for/{id}/edit",
                axum::routing::get(get_edit_waiting_for).post(post_edit_waiting_for),
            )
            .route("/someday-maybe", axum::routing::get(get_someday_maybe))
            .route("/review", axum::routing::get(get_review))
            .route(
                "/register",
                axum::routing::get(get_register).post(post_register),
            )
            .route("/login", axum::routing::get(get_login).post(post_login))
            .route("/forgot-password", axum::routing::get(get_forgot_password))
            .route("/logout", axum::routing::post(post_logout))
            .route("/todos", axum::routing::get(get_todos_page).post(post_todo))
            .route("/todos/{id}", axum::routing::get(get_todo_item))
            .route("/todos/{id}/toggle", axum::routing::post(post_toggle_todo))
            .route("/todos/{id}/delete", axum::routing::post(post_delete_todo))
            .route(
                "/todos/{id}/edit",
                axum::routing::get(get_edit_todo).post(post_edit_todo),
            )
            .route("/health_check", axum::routing::get(health_check))
            .nest_service("/static", ServeDir::new("static"))
            .layer(session_layer)
            .layer(TraceLayer::new_for_http())
            .layer(PropagateRequestIdLayer::new(x_request_id.clone()))
            .layer(SetRequestIdLayer::new(x_request_id, MakeRequestUuid))
            .with_state(pool)
    }

    pub async fn run(self) -> Result<(), std::io::Error> {
        let router = Self::router(self.pool);
        axum::serve(self.listener, router).await
    }
}

