 41→/// Helper: extract a waiting-for item ID from the page body.
 42→fn extract_waiting_for_id(body: &str) -> String {
 43→    // Look for action="/waiting-for/<uuid>/complete"
 44→    let action_prefix = "action=\"/waiting-for/";
 45→    let start = body
 46→        .find(action_prefix)
 47→        .expect("Missing waiting-for action in body")
 48→        + action_prefix.len();
 49→    let end = body[start..].find('/').expect("Missing / after UUID");
 50→    body[start..start + end].to_string()
 51→}
